type DashboardState = typeof defaultState;

function mergeState(raw: Partial<DashboardState>): DashboardState {
  return { ...defaultState, ...raw, account: { ...defaultState.account, ...(raw.account || {}) }, pet: { ...defaultState.pet, ...(raw.pet || {}) }, vet: { ...defaultState.vet, ...(raw.vet || {}) }, settings: { ...defaultState.settings, ...(raw.settings || {}) }, subscription: { ...defaultState.subscription, ...(raw.subscription || {}) }, goals: { ...defaultState.goals, ...(raw.goals || {}) }, walks: raw.walks || defaultState.walks, savedRoutes: raw.savedRoutes || defaultState.savedRoutes, meals: raw.meals || defaultState.meals, records: raw.records || defaultState.records, lostReports: raw.lostReports || defaultState.lostReports, packFriends: raw.packFriends || defaultState.packFriends, packGroups: raw.packGroups || defaultState.packGroups, packMessages: raw.packMessages || defaultState.packMessages, training: raw.training || defaultState.training, play: raw.play || defaultState.play, achievements: raw.achievements || defaultState.achievements, managedUsers: raw.managedUsers || defaultState.managedUsers, reminders: raw.reminders || defaultState.reminders };
}

function loadState() {
  if (typeof window === 'undefined') return defaultState;
  try { return mergeState(JSON.parse(localStorage.getItem('mypetid.dashboard') || '{}')); } catch { return defaultState; }
}

function ageFromBirthday(value: string) {
  if (!value) return 'Birthday not set';
  const birth = new Date(`${value}T00:00:00`);
  if (Number.isNaN(birth.getTime())) return 'Birthday not set';
  const now = new Date();
  let years = now.getFullYear() - birth.getFullYear();
  let months = now.getMonth() - birth.getMonth();
  if (now.getDate() < birth.getDate()) months -= 1;
  if (months < 0) { years -= 1; months += 12; }
  return years > 0 ? `${years} yr ${months} mo` : `${Math.max(0, months)} mo`;
}

function formatCoords(coords?: Coords) {
  if (!coords) return 'Waiting for device GPS';
  return `${coords.label}: ${coords.lat.toFixed(5)}, ${coords.lng.toFixed(5)}${coords.accuracy ? ` ±${Math.round(coords.accuracy)}m` : ''}`;
}

function walkMapUrl(start?: Coords, end?: Coords) {
  const fallback = 'https://maps.google.com/maps?q=44.097371370963934,-70.16535158888728&z=14&output=embed';
  if (start && end) return `https://maps.google.com/maps?saddr=${start.lat},${start.lng}&daddr=${end.lat},${end.lng}&z=15&output=embed`;
  const point = start || end;
  return point ? `https://maps.google.com/maps?q=${point.lat},${point.lng}&z=15&output=embed` : fallback;
}

function Field({ label, value, onChange, type = 'text', hint, min }: { label: string; value: string; type?: string; hint?: string; min?: string; onChange: (value: string) => void }) {
  return <label>{label}<input min={min} type={type} value={value} onChange={(event) => onChange(event.target.value)} />{hint && <small>{hint}</small>}</label>;
}
function SelectField({ label, value, options, onChange }: { label: string; value: string; options: string[]; onChange: (value: string) => void }) {
  return <label>{label}<select value={value} onChange={(event) => onChange(event.target.value)}>{options.map((option) => <option key={option} value={option}>{option}</option>)}</select></label>;
}
function TextArea({ label, value, onChange }: { label: string; value: string; onChange: (value: string) => void }) {
  return <label>{label}<textarea value={value} onChange={(event) => onChange(event.target.value)} /></label>;
}
function ImageUpload({ label, onLoaded }: { label: string; onLoaded: (dataUrl: string) => void }) {
  return <label>{label}<input type="file" accept="image/*" onChange={(event) => { const file = event.target.files?.[0]; if (!file) return; const reader = new FileReader(); reader.onload = () => onLoaded(String(reader.result || '')); reader.readAsDataURL(file); }} /><small>Previewed in this browser now; production should store private files in Supabase Storage with owner/admin RLS.</small></label>;
}
function milesBetween(start?: Coords, end?: Coords) { if (!start || !end) return 0; const toRad = (value: number) => value * Math.PI / 180; const r = 3958.8; const dLat = toRad(end.lat - start.lat); const dLng = toRad(end.lng - start.lng); const a = Math.sin(dLat / 2) ** 2 + Math.cos(toRad(start.lat)) * Math.cos(toRad(end.lat)) * Math.sin(dLng / 2) ** 2; return Number((2 * r * Math.asin(Math.sqrt(a))).toFixed(3)); }
function coordsFromPosition(position: GeolocationPosition, label: string): Coords { return { lat: position.coords.latitude, lng: position.coords.longitude, accuracy: position.coords.accuracy, timestamp: position.timestamp, label }; }
function canUseDirectDistance(start?: Coords, end?: Coords) { return Boolean(start && end && (start.accuracy || 999) <= 50 && (end.accuracy || 999) <= 50 && milesBetween(start, end) >= 0.02); }
function statusBadge(status: string) { if (status.includes('Service')) return '🦮'; if (status.includes('Therapy')) return '💙'; if (status.includes('Emotional')) return '💚'; if (status.includes('Working')) return '⭐'; return ''; }
function rescueBadge(status: string) { return status && status !== 'Not set' ? '🏠' : ''; }

export function DashboardClient() {
  const [state, setState] = useState(defaultState);
  const [activeTab, setActiveTab] = useState<Tab>('overview');
  const [message, setMessage] = useState('Ready. Finish one section, then use Next to keep the app flowing section by section.');
  const [walking, setWalking] = useState(false);
  const [walkSeconds, setWalkSeconds] = useState(0);
  const [walkMiles, setWalkMiles] = useState(0);
  const [walkStart, setWalkStart] = useState<Coords | undefined>();
  const [walkEnd, setWalkEnd] = useState<Coords | undefined>();
  const [walkEndMode, setWalkEndMode] = useState<WalkEndMode>('start');
  const [packDraft, setPackDraft] = useState('Who wants to hit the park this afternoon?');
  const [packGroup, setPackGroup] = useState('Park crew');
  const [userDraft, setUserDraft] = useState({ name: 'New Owner', email: 'owner@example.com', role: 'User' });
  const [routeDraft, setRouteDraft] = useState({ name: 'Custom loop', startLabel: 'Home', endLabel: 'Home', stopsText: 'Park corner, water break', distance: '1.5', notes: 'Owner-planned safe route.' });
  const [customGroup, setCustomGroup] = useState('Neighborhood pack');
  const [menuOpen, setMenuOpen] = useState(false);
  const [showSettings, setShowSettings] = useState(false);
  const [gpsStatus, setGpsStatus] = useState('GPS idle. Start a walk to request Android location permission.');
  const [lastGpsFix, setLastGpsFix] = useState<Coords | undefined>();

  useEffect(() => setState(loadState()), []);
  useEffect(() => { document.documentElement.dataset.theme = state.theme; document.documentElement.dataset.palette = state.palette; localStorage.setItem('mypetid.dashboard', JSON.stringify(state)); }, [state]);
  useEffect(() => { if (!walking) return; const timer = window.setInterval(() => setWalkSeconds((value) => value + 1), 1000); return () => clearInterval(timer); }, [walking]);
  useEffect(() => {
    if (!walking || !navigator.geolocation) return;
    const watcher = navigator.geolocation.watchPosition((position) => {
      const coords = coordsFromPosition(position, 'Live GPS fix');
      setWalkEnd(coords);
      setLastGpsFix((previous) => {
        if (previous) {
          const segment = milesBetween(previous, coords);
          const seconds = Math.max(1, ((coords.timestamp || Date.now()) - (previous.timestamp || Date.now())) / 1000);
          const mph = segment / (seconds / 3600);
          const accurateEnough = (coords.accuracy || 999) <= 35 && (previous.accuracy || 999) <= 35;
          const movedFarEnough = segment >= 0.02;
          if (accurateEnough && movedFarEnough && mph <= 12) {
            setWalkMiles((miles) => Number((miles + segment).toFixed(2)));
            setGpsStatus(`GPS tracking from Android: +${segment.toFixed(2)} mi, ${Math.round(coords.accuracy || 0)}m accuracy.`);
          } else {
            setGpsStatus(`GPS fix held: ${Math.round(coords.accuracy || 0)}m accuracy, ${segment.toFixed(3)} mi shift ignored to prevent bed/couch drift.`);
          }
        } else {
          setGpsStatus(`GPS locked: ${formatCoords(coords)}.`);
        }
        return coords;
      });
    }, (error) => setGpsStatus(`Android location is not available yet: ${error.message}`), { enableHighAccuracy: true, maximumAge: 3000, timeout: 12000 });
    return () => navigator.geolocation.clearWatch(watcher);
  }, [walking]);

  const pet = state.pet;
  const vet = state.vet;
  const account = state.account;
  const petAge = ageFromBirthday(pet.birthday);
  const weeklyDone = state.walks.reduce((sum, walk) => sum + walk.distance, 0) + walkMiles;
  const weeklyProgress = Math.min(100, Math.round((weeklyDone / Math.max(1, state.goals.weeklyMiles)) * 100));
  const publicUrl = useMemo(() => typeof window === 'undefined' ? `/scan/?tag=${pet.tagId}` : `${window.location.origin}/scan/?tag=${encodeURIComponent(pet.tagId)}`, [pet.tagId]);
  const readOnlyUrl = `/pet/?tag=${encodeURIComponent(pet.tagId)}`;
  const currentIndex = tabs.indexOf(activeTab);
  const nextTab = tabs[Math.min(tabs.length - 1, currentIndex + 1)];
  const prevTab = tabs[Math.max(0, currentIndex - 1)];
  const earnedXp = state.achievements.filter((item) => item.earned).reduce((sum, item) => sum + item.points, 0);
  const canSeeAdmin = state.adminMode || state.tier === 'admin';
  const navTabs = canSeeAdmin ? [...tabs, 'admin' as Tab] : tabs;
  const lostAlertCount = state.lostReports.filter((report) => report.status !== 'Resolved' && report.status !== 'False alarm').length;
  const activeTier = state.subscription.patreonLinked ? state.subscription.patreonTier : 'free';
  const petLimitLabel = state.subscription.patreonLinked ? tiers[state.subscription.patreonTier].pets : tiers.free.pets;

  function patchAccount(next: Partial<AccountProfile>) { setState({ ...state, account: { ...account, ...next } }); }
  function patchPet(next: Partial<PetProfile>) { setState({ ...state, pet: { ...pet, ...next } }); }
  function patchVet(next: Partial<VetProfile>) { setState({ ...state, vet: { ...vet, ...next } }); }
  function patchSettings(next: Partial<typeof state.settings>) { setState({ ...state, settings: { ...state.settings, ...next } }); }
  function finishSection(next: Tab = nextTab) { setActiveTab(next); setMessage(`Saved this section locally. Next up: ${tabLabels[next]}.`); window.scrollTo({ top: 0, behavior: 'smooth' }); }
  function goBack() { setActiveTab(prevTab); setMessage(`Back to ${tabLabels[prevTab]}.`); window.scrollTo({ top: 0, behavior: 'smooth' }); }
  function awardXp(points: number, reason: string) { const currentXp = state.goals.currentXp + points; const level = Math.max(state.goals.level, Math.floor(currentXp / 250) + 1); setState({ ...state, goals: { ...state.goals, currentXp, level } }); setMessage(`+${points} XP: ${reason}`); }
  function captureLocation(label: string, callback: (coords: Coords) => void) {
    if (!navigator.geolocation) { setMessage('This Android browser/webview does not expose location services. Install/open in Chrome and enable Location for MyPetID.'); setGpsStatus('No browser geolocation API available.'); return; }
    navigator.geolocation.getCurrentPosition((position) => { const coords = coordsFromPosition(position, label); callback(coords); setGpsStatus(`${label}: ${formatCoords(coords)}.`); setMessage(`${label} saved from this device.`); }, (error) => { setGpsStatus(`${label} blocked: ${error.message}`); setMessage('Location permission was denied or unavailable. No demo distance was added.'); }, { enableHighAccuracy: true, timeout: 12000, maximumAge: 3000 });
  }
  async function savePetToSupabase() {
    if (!supabase) return setMessage('Supabase is not configured in this build; data is saved locally and routed through previews.');
    const { data: auth } = await supabase.auth.getUser();
    if (!auth.user) return setMessage('Sign in first before saving pet data to Supabase.');
    const { error } = await supabase.from('pets').upsert({ owner_id: auth.user.id, name: pet.name, species: pet.species.toLowerCase(), breed: pet.breed, photo_url: pet.photoUrl, medical_public: pet.medicalNotes, behavior_public: pet.behaviorNotes, service_status: pet.serviceStatus, rescue_status: pet.rescueStatus, documents: state.records.map((record) => ({ title: record.title, kind: record.kind, date: record.date, public: record.public, has_image: Boolean(record.attachmentUrl) })), feeding_plan: pet.feeding, care_notes: `${pet.allergies}\n${pet.illnesses}\n${pet.medications}\nVet: ${vet.clinic} ${vet.phone}` });
    setMessage(error ? error.message : 'Pet profile saved to Supabase. Public profile and dashboard previews are already updated locally.');
  }
  function startWalk() { setWalking(true); setWalkSeconds(0); setWalkMiles(0); setWalkEnd(undefined); setLastGpsFix(undefined); setGpsStatus('Requesting high-accuracy Android GPS…'); captureLocation('Walk start', (coords) => { setWalkStart(coords); setLastGpsFix(coords); }); }
  function endWalk(mode = walkEndMode) { captureLocation('Walk end', (coords) => { const direct = canUseDirectDistance(walkStart, coords) ? milesBetween(walkStart, coords) : 0; const distance = Number(Math.max(walkMiles, direct).toFixed(2)); const entry = { id: Date.now(), start: 'Just now', end: `Ended by ${mode}`, distance, duration: Math.max(1, Math.round(walkSeconds / 60)), mode, routeName: state.savedRoutes[0]?.name, routeStops: state.savedRoutes[0]?.stops, notes: `Android GPS tracked only. Planned routes do not auto-add distance. ${formatCoords(walkStart)} to ${formatCoords(coords)}.`, startCoords: walkStart, endCoords: coords }; setState({ ...state, walks: [entry, ...state.walks], goals: { ...state.goals, currentXp: state.goals.currentXp + 50, level: Math.max(state.goals.level, Math.floor((state.goals.currentXp + 50) / 250) + 1) } }); setWalkMiles(distance); setWalkEnd(coords); setWalking(false); setGpsStatus(distance > 0 ? `Walk saved with ${distance} mi from GPS.` : 'Walk saved with 0.00 mi; GPS drift or missing permission was ignored.'); setMessage(`Walk saved: ${entry.distance} mi, ${walkSeconds}s, ended by ${mode}. +50 XP. No distance is added while standing still.`); }); }
  function addMeal() { setState({ ...state, meals: [{ id: Date.now(), time: '12:00 PM', meal: 'Snack', amount: 'Custom amount', calories: 120, done: false }, ...state.meals] }); }
  function addRecord() { setState({ ...state, records: [{ id: Date.now(), title: 'New record', kind: 'Medical', date: new Date().toISOString().slice(0, 10), notes: 'Editable notes', public: false, attachmentUrl: '' }, ...state.records] }); }
  function saveRoute() { const route = { id: Date.now(), name: routeDraft.name || 'Custom route', startLabel: routeDraft.startLabel || 'Start', endLabel: routeDraft.endLabel || 'End', stops: routeDraft.stopsText.split(',').map((item) => item.trim()).filter(Boolean), distance: Number(routeDraft.distance) || 0, notes: routeDraft.notes }; setState({ ...state, savedRoutes: [route, ...state.savedRoutes] }); setMessage(`Saved walk route: ${route.name}.`); }
  function addPackGroup() { const group = customGroup.trim(); if (!group) return; setState({ ...state, packGroups: Array.from(new Set([group, ...state.packGroups])) }); setPackGroup(group); setCustomGroup(''); setMessage(`Dog Pack group saved: ${group}.`); }
  function addReminder(category = 'Feed') { setState({ ...state, reminders: [{ id: Date.now(), title: `New ${category.toLowerCase()} reminder`, category, time: '12:00', repeat: 'Daily', enabled: true }, ...state.reminders] }); setMessage(`${category} reminder added.`); }
  function linkPatreonDemo(tier: keyof typeof tiers = 'silver') { setState({ ...state, tier, subscription: { ...state.subscription, patreonLinked: true, patreonTier: tier, patreonStatus: `Verified ${tiers[tier].label}` } }); setMessage(`Patreon linked locally as ${tiers[tier].label}. Production verification will use Supabase Edge Functions.`); }
  function toggleGoogle(kind: 'googlePhotos' | 'googleDrive' | 'googleCalendar') { setState({ ...state, subscription: { ...state.subscription, [kind]: !state.subscription[kind] } }); setMessage('Google integration staged. Credentials/OAuth consent are still required before live sync.'); }
  function reportLostFromOwner() { captureLocation('Owner lost report', (coords) => { setState({ ...state, lostReports: [{ id: Date.now(), status: 'Open', location: formatCoords(coords), note: 'Owner reported lost from dashboard. Red alert active until resolved.', time: 'Now' }, ...state.lostReports] }); setMessage('🔴 Lost dog alert created with the current device location.'); }); }
  function addLostReport(status = 'Open') { setState({ ...state, lostReports: [{ id: Date.now(), status, location: 'New sighting location', note: 'Editable lost/found note', time: 'Now' }, ...state.lostReports] }); }
  function sendPackMessage() { if (!packDraft.trim()) return; setState({ ...state, packMessages: [{ id: Date.now(), author: account.displayName, text: packDraft, group: packGroup, time: 'Now' }, ...state.packMessages] }); setPackDraft(''); setMessage('Dog Pack message posted locally. Production chat should persist through Supabase realtime.'); }
  function addManagedUser() { setState({ ...state, managedUsers: [{ id: Date.now(), role: userDraft.role, name: userDraft.name, email: userDraft.email, plan: 'free', pets: 0, status: 'Invited' }, ...state.managedUsers] }); setMessage(`Admin invite staged for ${userDraft.email}. Production email invite belongs behind Supabase admin/Edge Function.`); }
  function sectionNav() { return <div className="sectionNav"><button type="button" onClick={goBack} disabled={currentIndex === 0}>Back</button><button className="primary" type="button" onClick={() => finishSection()} disabled={currentIndex === tabs.length - 1}>Save + Next: {tabLabels[nextTab]}</button></div>; }

  return (
    <main className="appShell proApp">
      <button className="hamburger topLeft" type="button" onClick={() => setMenuOpen(!menuOpen)} aria-expanded={menuOpen}>☰</button>
      <aside className={`sidebar ${menuOpen ? 'open' : ''}`}>
        <nav className="sideNav" aria-label="Dashboard sections">{navTabs.map((tab) => <button key={tab} className={activeTab === tab ? 'active' : ''} onClick={() => { setActiveTab(tab); setMenuOpen(false); }} type="button">{tabLabels[tab]}{tab === 'lost' && lostAlertCount > 0 ? <span className="alertDot">{lostAlertCount}</span> : null}</button>)}</nav>
        <div className={`tierBadge ${state.tier === 'admin' ? 'red' : 'green'}`}><span>{state.adminMode ? 'Admin view' : tiers[activeTier].label}</span><strong>{petLimitLabel} pets • {tiers[activeTier].users} users</strong><small>{state.subscription.patreonLinked ? state.subscription.patreonStatus : 'Patreon not linked — Free limits active'}</small></div>
      </aside>
      <section className="workspace">
        <header className="appHeader"><div><p className="eyebrow">Production command center</p><h1>{state.adminMode ? 'Admin app studio' : `${pet.name}'s life tracker`}</h1><p>Onboard the owner, dog profile, NFC tag, care reminders, lost/found alerts, Patreon tier, and connected storage one step at a time.</p></div><button className="profileTopRight" type="button" onClick={() => setActiveTab('account')}><img src={account.avatarUrl || '/images/logo/MyPetID-Logo_Resized.jpg'} alt={account.displayName} /><span>{account.displayName}</span><small>{state.subscription.patreonLinked ? state.subscription.patreonStatus : 'Link Patreon'}</small>{lostAlertCount > 0 && <strong className="redAlert">{lostAlertCount}</strong>}</button></header>
        <nav className="mobileSectionNav" aria-label="Quick dashboard sections">{navTabs.map((tab) => <button key={tab} className={activeTab === tab ? 'active' : ''} onClick={() => setActiveTab(tab)} type="button">{tabLabels[tab]}{tab === 'lost' && lostAlertCount > 0 ? <span className="alertDot">{lostAlertCount}</span> : null}</button>)}</nav>
        {!hasSupabaseConfig && <p className="notice">Demo mode: Supabase public env values are missing from this static build, so edits save locally in this browser and flow through the UI.</p>}
        <AuthPanel />
        <SupabaseWorkspace />
        <div className="dashboardStatus"><span>{message}</span><div className="actions compact">{state.tier === 'admin' && <button type="button" onClick={() => setState({ ...state, adminMode: !state.adminMode })}>{state.adminMode ? 'Use as user' : 'Switch to admin'}</button>}<button type="button" onClick={() => setState({ ...state, theme: state.theme === 'dark' ? 'light' : 'dark' })}>{state.theme === 'dark' ? 'Light mode' : 'Dark mode'}</button></div></div>

        {activeTab === 'overview' && <div className="dashboardGrid"><section className="panel heroPanel"><div><p className="eyebrow">NFC-ready profile</p><h2>{pet.name} <span className="inlineBadges">{statusBadge(pet.serviceStatus)}{rescueBadge(pet.rescueStatus)}</span></h2><p>{pet.breed} • {petAge} • {pet.size} • {pet.weight} lb • tag {pet.tagId}</p><div className="actions"><Link className="button primary" href={`/scan/?tag=${encodeURIComponent(pet.tagId)}`}>Open scan gate</Link><Link className="button" href={readOnlyUrl}>Public profile</Link><button type="button" onClick={savePetToSupabase}>Save pet</button></div></div><QRCodeSVG value={publicUrl} size={160} bgColor="transparent" fgColor="currentColor" /></section><section className="panel stat"><p>Weekly walks</p><strong>{weeklyDone.toFixed(1)} mi</strong><div className="progress"><span style={{ width: `${weeklyProgress}%` }} /></div><span>{weeklyProgress}% of {state.goals.weeklyMiles} mi</span></section><section className="panel stat"><p>Care level</p><strong>Lv {state.goals.level}</strong><span>{state.goals.currentXp + earnedXp} XP total</span></section><section className="panel stat"><p>Training</p><strong>{state.training.filter((item) => item.status === 'Mastered').length}/{state.training.length}</strong><span>commands mastered</span></section><section className="panel wide"><h2>Live walk map</h2><p className="formHint">Timer runs while walking. Distance now comes from high-accuracy Android GPS movement only; planned routes stay separate and couch/bed drift is ignored.</p><div className="realMap"><iframe title="Live walk map" src={walkMapUrl(walkStart, walkEnd)} loading="lazy" /></div><div className="routeMeta"><span>{formatCoords(walkStart)}</span><span>{formatCoords(walkEnd)}</span></div><p className="gpsStatus">{gpsStatus}</p><div className="actions">{walking ? <button className="primary" type="button" onClick={() => endWalk(walkEndMode)}>End walk</button> : <button className="primary" type="button" onClick={startWalk}>Start walk</button>}<span>{walkMiles.toFixed(2)} mi • {walkSeconds}s</span></div></section></div>}

        {activeTab === 'public' && <div className="dashboardGrid"><section className="panel wide"><p className="eyebrow">Public profile preview</p><h2>What finders, friends, and approved viewers see</h2><div className="publicPreview"><div className="photoBadgeWrap"><img src={pet.photoUrl} alt={pet.name} />{statusBadge(pet.serviceStatus) && <span className="profileStatusBadge" title={pet.serviceStatus}>{statusBadge(pet.serviceStatus)}</span>}{rescueBadge(pet.rescueStatus) && <span className="profileStatusBadge rescue" title={pet.rescueStatus}>{rescueBadge(pet.rescueStatus)}</span>}</div><div><h3>{pet.name}</h3><p>{pet.breed} • {petAge} • {pet.size}</p><p>{state.settings.publicBehavior ? pet.behaviorNotes : 'Behavior notes hidden'}</p><dl className="infoList"><dt>Status badges</dt><dd>{pet.serviceStatus} {pet.rescueStatus !== 'Not set' ? `• ${pet.rescueStatus}` : ''}</dd><dt>Owner-approved medical</dt><dd>{state.settings.publicMedical ? pet.medicalNotes : 'Hidden by privacy settings'}</dd><dt>Contact route</dt><dd>{state.settings.publicContact ? `${account.displayName} via ${account.phone}` : 'Contact hidden'}</dd><dt>Last safe scan</dt><dd>{state.settings.shareLastScan ? 'Map visible during owner-approved mode' : 'Hidden'}</dd></dl><div className="actions"><Link className="button primary" href={readOnlyUrl}>Open public route</Link><button type="button" onClick={() => setActiveTab('settings')}>Edit visibility</button></div></div></div></section><section className="panel"><h3>Routes</h3><p>NFC scan writes only after consent:</p><code>{publicUrl}</code><p>Read-only profile:</p><code>{readOnlyUrl}</code></section></div>}

        {activeTab === 'account' && <div className="dashboardGrid"><section className="panel wide"><h2>Account information</h2><p className="formHint">These fields feed the dashboard header, public contact preview, admin user list, and invite/account routes.</p><div className="grid2"><Field label="Username" value={account.username} onChange={(v) => patchAccount({ username: v })} /><Field label="Display name" value={account.displayName} onChange={(v) => patchAccount({ displayName: v })} /><Field label="Email" type="email" value={account.email} onChange={(v) => patchAccount({ email: v })} /><Field label="Phone" value={account.phone} onChange={(v) => patchAccount({ phone: v })} /><Field label="Profile picture URL" value={account.avatarUrl} onChange={(v) => patchAccount({ avatarUrl: v })} /><Field label="Emergency contact" value={account.emergencyContact} onChange={(v) => patchAccount({ emergencyContact: v })} /></div><TextArea label="Private address" value={account.address} onChange={(v) => patchAccount({ address: v })} /></section><section className="panel"><img className="profilePreview" src={account.avatarUrl} alt={account.displayName} /><h3>{account.displayName}</h3><p>@{account.username}</p><p>{account.passwordLabel}</p><button type="button" onClick={() => setShowSettings(!showSettings)}>{showSettings ? 'Close settings' : 'Open settings'}</button><button type="button" onClick={() => setMessage('Password resets should use Supabase Auth reset email; no password is stored in the static app.')}>Send password reset</button></section>{showSettings && <section className="panel wide"><h2>Account settings</h2><div className="grid2"><SelectField label="Units" value={state.settings.units} options={['miles','kilometers']} onChange={(v) => patchSettings({ units: v })} /><SelectField label="Privacy mode" value={state.settings.privacyMode} options={['strict','balanced','open during lost mode']} onChange={(v) => patchSettings({ privacyMode: v })} /><SelectField label="App color palette" value={state.palette} options={['forest','ocean','sunset','mono']} onChange={(v) => setState({ ...state, palette: v as Palette })} /><SelectField label="Theme" value={state.theme} options={['dark','light']} onChange={(v) => setState({ ...state, theme: v as Theme })} /></div>{Object.entries(state.settings).map(([key, value]) => typeof value === 'boolean' ? <label className="toggleRow" key={key}><input type="checkbox" checked={value} onChange={(event) => patchSettings({ [key]: event.target.checked } as Partial<typeof state.settings>)} /> {key}</label> : null)}</section>}<section className="panel wide"><h2>Membership and connected storage</h2><div className="grid2"><label>Patreon status<input readOnly value={state.subscription.patreonStatus} /></label><SelectField label="Verified tier preview" value={state.subscription.patreonTier} options={Object.keys(tiers)} onChange={(v) => setState({ ...state, subscription: { ...state.subscription, patreonTier: v as keyof typeof tiers } })} /></div><div className="actions"><Link className="button primary" href="/verify/patreon/">Link Patreon</Link><button type="button" onClick={() => linkPatreonDemo(state.subscription.patreonTier)}>Mark Patreon verified locally</button></div><div className="tierMatrix">{(Object.keys(tiers) as Array<keyof typeof tiers>).map((tier) => <div className={tier === activeTier ? 'tierCard active' : 'tierCard'} key={tier}><strong>{tiers[tier].label}</strong><small>{tiers[tier].pets} pets • {tiers[tier].users} users</small>{tierFeatures[tier].map((feature) => <span key={feature}>{feature}</span>)}</div>)}</div></section><section className="panel wide"><h2>Google + Supabase storage plan</h2><p className="formHint">Google credentials are pending. The UI is ready to ask permission before connecting Photos, Drive, or Calendar.</p><div className="serviceGrid"><button className={state.subscription.googlePhotos ? 'servicePill green' : 'servicePill yellow'} type="button" onClick={() => toggleGoogle('googlePhotos')}><span />Google Photos dog galleries</button><button className={state.subscription.googleDrive ? 'servicePill green' : 'servicePill yellow'} type="button" onClick={() => toggleGoogle('googleDrive')}><span />Google Drive care exports</button><button className={state.subscription.googleCalendar ? 'servicePill green' : 'servicePill yellow'} type="button" onClick={() => toggleGoogle('googleCalendar')}><span />Google Calendar planned events</button><div className="servicePill green"><span />Supabase profile photos + documents</div></div><div className="actions"><Link className="button" href="/verify/google/">Review Google permissions</Link></div></section></div>}

        {activeTab === 'pets' && <div className="dashboardGrid"><section className="panel wide"><h2>Pet profile details</h2><p className="formHint">Birthday calculates age; numeric measurements stay numeric; normalized dropdowns keep profiles searchable.</p><div className="grid2"><Field label="Name" value={pet.name} onChange={(v) => patchPet({ name: v })} /><Field label="Tag ID" value={pet.tagId} onChange={(v) => patchPet({ tagId: v })} /><SelectField label="Species" value={pet.species} options={['Dog']} onChange={(v) => patchPet({ species: v })} /><SelectField label="Breed" value={pet.breed} options={breedOptions} onChange={(v) => patchPet({ breed: v })} /><Field label="Birthday" type="date" value={pet.birthday} hint={`Age: ${petAge}`} onChange={(v) => patchPet({ birthday: v })} /><SelectField label="Sex" value={pet.sex} options={['Male','Female','Neutered male','Spayed female','Unknown']} onChange={(v) => patchPet({ sex: v })} /><SelectField label="Size" value={pet.size} options={sizeBands} onChange={(v) => patchPet({ size: v })} /><SelectField label="Eye color" value={pet.eyeColor} options={eyeColors} onChange={(v) => patchPet({ eyeColor: v })} /><SelectField label="Coat color" value={pet.coatColor} options={coatColors} onChange={(v) => patchPet({ coatColor: v })} /><SelectField label="Coat type" value={pet.coatType} options={coatTypes} onChange={(v) => patchPet({ coatType: v })} /><Field label="Weight (lb)" type="number" min="0" value={pet.weight} onChange={(v) => patchPet({ weight: v })} /><Field label="Height (in)" type="number" min="0" value={pet.height} onChange={(v) => patchPet({ height: v })} /><Field label="Length (in)" type="number" min="0" value={pet.length} onChange={(v) => patchPet({ length: v })} /><Field label="Microchip" value={pet.microchip} onChange={(v) => patchPet({ microchip: v })} /><SelectField label="Service / work status" value={pet.serviceStatus} options={serviceStatusOptions} onChange={(v) => patchPet({ serviceStatus: v })} /><SelectField label="Rescue status" value={pet.rescueStatus} options={rescueStatusOptions} onChange={(v) => patchPet({ rescueStatus: v })} /><Field label="Home base" value={pet.homeBase} onChange={(v) => patchPet({ homeBase: v })} /><Field label="Photo URL" value={pet.photoUrl} onChange={(v) => patchPet({ photoUrl: v })} /></div><TextArea label="Behavior notes" value={pet.behaviorNotes} onChange={(v) => patchPet({ behaviorNotes: v })} /><TextArea label="Certificates / IDs" value={pet.certifications} onChange={(v) => patchPet({ certifications: v })} /></section><section className="panel"><h3>Pet summary</h3><p>{pet.name} is a {petAge} {pet.breed}.</p><p>{pet.eyeColor} eyes • {pet.coatColor} {pet.coatType} coat</p><p>{pet.size} • {pet.weight} lb • {pet.height} in tall • {pet.length} in long</p><p>{pet.serviceStatus} • {pet.rescueStatus}</p><div className="actions"><Link className="button primary" href={readOnlyUrl}>Preview public NFC profile</Link><button type="button" onClick={() => setActiveTab('training')}>Training setup</button><button type="button" onClick={() => setActiveTab('play')}>Play setup</button><button type="button" onClick={() => setActiveTab('goals')}>Goals / XP setup</button></div></section><section className="panel wide"><h2>Training, play, and goals</h2><p className="formHint">These setup sections now live under the dog profile flow instead of crowding the main menu.</p><div className="chipCloud"><span>{state.training.length} training items</span><span>{state.play.length} play activities</span><span>Level {state.goals.level}</span><span>{state.goals.currentXp + earnedXp} XP</span></div></section></div>}

        {activeTab === 'walks' && <div className="dashboardGrid"><section className="panel wide"><h2>Walk and route planner</h2><p className="formHint">Build custom routes, save them, then pick one before a walk. Live distance uses Android high-accuracy GPS only. Saved route mileage is a plan/estimate and will not be auto-counted as walked.</p><div className="grid2"><SelectField label="End walk by" value={walkEndMode} options={['destination','start','home','custom']} onChange={(v) => setWalkEndMode(v as WalkEndMode)} /><Field label="Custom destination" value={state.settings.customDestination} onChange={(v) => patchSettings({ customDestination: v })} /><Field label="Route name" value={routeDraft.name} onChange={(v) => setRouteDraft({ ...routeDraft, name: v })} /><Field label="Planned miles" type="number" min="0" value={routeDraft.distance} onChange={(v) => setRouteDraft({ ...routeDraft, distance: v })} /><Field label="Start label" value={routeDraft.startLabel} onChange={(v) => setRouteDraft({ ...routeDraft, startLabel: v })} /><Field label="End label" value={routeDraft.endLabel} onChange={(v) => setRouteDraft({ ...routeDraft, endLabel: v })} /></div><TextArea label="Stops / waypoints, comma separated" value={routeDraft.stopsText} onChange={(v) => setRouteDraft({ ...routeDraft, stopsText: v })} /><TextArea label="Route notes" value={routeDraft.notes} onChange={(v) => setRouteDraft({ ...routeDraft, notes: v })} /><div className="realMap"><iframe title="Walk route map" src={walkMapUrl(walkStart, walkEnd)} loading="lazy" /></div><div className="routeMeta"><span>Start: {formatCoords(walkStart)}</span><span>End: {formatCoords(walkEnd)}</span></div><div className="actions">{walking ? <button className="primary" type="button" onClick={() => endWalk(walkEndMode)}>End walk</button> : <button className="primary" type="button" onClick={startWalk}>Start walk</button>}<button type="button" onClick={saveRoute}>Save custom route</button><button type="button" onClick={() => captureLocation('Destination', setWalkEnd)}>Set destination from device</button><span>{walkMiles.toFixed(2)} mi live</span></div><p className="gpsStatus">{gpsStatus}</p></section><section className="panel wide"><h3>Saved routes</h3>{state.savedRoutes.map((route) => <div className="routeCard" key={route.id}><strong>{route.name}</strong><p>{route.startLabel} → {route.stops.join(' → ')} → {route.endLabel}</p><small>{route.distance} mi • {route.notes}</small><div className="actions compact"><button type="button" onClick={() => { setRouteDraft({ name: route.name, startLabel: route.startLabel, endLabel: route.endLabel, stopsText: route.stops.join(', '), distance: String(route.distance), notes: route.notes }); setMessage(`Selected planned route: ${route.name}. Mileage stays an estimate until Android GPS records movement.`); }}>Choose route</button><button type="button" onClick={() => setState({ ...state, savedRoutes: state.savedRoutes.filter((item) => item.id !== route.id) })}>Delete</button></div></div>)}</section>{state.walks.map((walk) => <section className="panel" key={walk.id}><h3>{walk.distance} mi</h3><p>{walk.routeName || 'Custom walk'} • {walk.start} → {walk.end}</p><p>{walk.duration} min • {walk.mode || 'route'}</p><p>{walk.notes}</p></section>)}</div>}

        {activeTab === 'diet' && <div className="dashboardGrid"><section className="panel wide"><h2>Diet and meal tracker</h2><TextArea label="Feeding plan" value={pet.feeding} onChange={(v) => patchPet({ feeding: v })} /><Field label="Favorite treats" value={pet.favoriteTreats} onChange={(v) => patchPet({ favoriteTreats: v })} /><button className="primary" type="button" onClick={addMeal}>Add meal/snack</button></section>{state.meals.map((meal) => <section className="panel" key={meal.id}><label className="toggleRow"><input type="checkbox" checked={meal.done} onChange={(event) => setState({ ...state, meals: state.meals.map((item) => item.id === meal.id ? { ...item, done: event.target.checked } : item) })} /> Complete</label><Field label="Time" value={meal.time} onChange={(v) => setState({ ...state, meals: state.meals.map((item) => item.id === meal.id ? { ...item, time: v } : item) })} /><SelectField label="Meal" value={meal.meal} options={['Breakfast','Lunch','Dinner','Snack','Medication','Water','Custom']} onChange={(v) => setState({ ...state, meals: state.meals.map((item) => item.id === meal.id ? { ...item, meal: v } : item) })} /><Field label="Amount" value={meal.amount} onChange={(v) => setState({ ...state, meals: state.meals.map((item) => item.id === meal.id ? { ...item, amount: v } : item) })} /></section>)}<section className="panel wide"><h2>Notification alarms</h2><p className="formHint">Set feeding, walk, training, play, medication, or custom alerts. Browser push/mobile notification wiring comes after production app install permissions.</p><div className="actions"><button type="button" onClick={() => addReminder('Feed')}>Add feed alarm</button><button type="button" onClick={() => addReminder('Walk')}>Add walk alarm</button><button type="button" onClick={() => addReminder('Train')}>Add training alarm</button><button type="button" onClick={() => addReminder('Play')}>Add play alarm</button></div></section>{state.reminders.map((reminder) => <section className="panel" key={reminder.id}><Field label="Alarm title" value={reminder.title} onChange={(v) => setState({ ...state, reminders: state.reminders.map((item) => item.id === reminder.id ? { ...item, title: v } : item) })} /><SelectField label="Category" value={reminder.category} options={['Feed','Walk','Train','Play','Medication','Vet','Custom']} onChange={(v) => setState({ ...state, reminders: state.reminders.map((item) => item.id === reminder.id ? { ...item, category: v } : item) })} /><Field label="Time" type="time" value={reminder.time} onChange={(v) => setState({ ...state, reminders: state.reminders.map((item) => item.id === reminder.id ? { ...item, time: v } : item) })} /><SelectField label="Repeat" value={reminder.repeat} options={['Once','Daily','Weekdays','Weekends','Weekly','Custom']} onChange={(v) => setState({ ...state, reminders: state.reminders.map((item) => item.id === reminder.id ? { ...item, repeat: v } : item) })} /><label className="toggleRow"><input type="checkbox" checked={reminder.enabled} onChange={(event) => setState({ ...state, reminders: state.reminders.map((item) => item.id === reminder.id ? { ...item, enabled: event.target.checked } : item) })} /> Enabled</label></section>)}</div>}

        {activeTab === 'medical' && <div className="dashboardGrid"><section className="panel wide"><h2>Medical, vet, and certificates</h2><p className="formHint">Built around normal pet-care records: vet contact, last/next visit, vaccines, medications, illnesses, allergies, insurance, certificates, service/rescue notes, and emergency instructions.</p><div className="grid2"><Field label="Vet clinic" value={vet.clinic} onChange={(v) => patchVet({ clinic: v })} /><Field label="Vet / doctor" value={vet.doctor} onChange={(v) => patchVet({ doctor: v })} /><Field label="Vet phone" value={vet.phone} onChange={(v) => patchVet({ phone: v })} /><Field label="Emergency clinic" value={vet.emergencyClinic} onChange={(v) => patchVet({ emergencyClinic: v })} /><Field label="Last visit" type="date" value={vet.lastVisit} onChange={(v) => patchVet({ lastVisit: v })} /><Field label="Next visit" type="date" value={vet.nextVisit} onChange={(v) => patchVet({ nextVisit: v })} /></div><TextArea label="Vet address / location" value={vet.address} onChange={(v) => patchVet({ address: v })} /><TextArea label="Vet notes" value={vet.notes} onChange={(v) => patchVet({ notes: v })} /><div className="grid2"><TextArea label="Allergies" value={pet.allergies} onChange={(v) => patchPet({ allergies: v })} /><TextArea label="Illnesses / conditions" value={pet.illnesses} onChange={(v) => patchPet({ illnesses: v })} /><TextArea label="Surgeries / procedures" value={pet.surgeries} onChange={(v) => patchPet({ surgeries: v })} /><TextArea label="Medications" value={pet.medications} onChange={(v) => patchPet({ medications: v })} /><TextArea label="Insurance / policy" value={pet.insurance} onChange={(v) => patchPet({ insurance: v })} /><TextArea label="Medical public note" value={pet.medicalNotes} onChange={(v) => patchPet({ medicalNotes: v })} /></div><button className="primary" type="button" onClick={addRecord}>Add record/certificate</button></section>{state.records.map((record) => <section className="panel" key={record.id}><Field label="Title" value={record.title} onChange={(v) => setState({ ...state, records: state.records.map((item) => item.id === record.id ? { ...item, title: v } : item) })} /><SelectField label="Kind" value={record.kind} options={recordKinds} onChange={(v) => setState({ ...state, records: state.records.map((item) => item.id === record.id ? { ...item, kind: v } : item) })} /><Field label="Date" type="date" value={record.date} onChange={(v) => setState({ ...state, records: state.records.map((item) => item.id === record.id ? { ...item, date: v } : item) })} /><TextArea label="Notes" value={record.notes} onChange={(v) => setState({ ...state, records: state.records.map((item) => item.id === record.id ? { ...item, notes: v } : item) })} />{record.attachmentUrl && <img className="medicalPreview" src={record.attachmentUrl} alt={record.title} />}<ImageUpload label="Upload record/certificate/ID picture" onLoaded={(dataUrl) => setState({ ...state, records: state.records.map((item) => item.id === record.id ? { ...item, attachmentUrl: dataUrl } : item) })} /><label className="toggleRow"><input type="checkbox" checked={record.public} onChange={(event) => setState({ ...state, records: state.records.map((item) => item.id === record.id ? { ...item, public: event.target.checked } : item) })} /> Public-safe</label></section>)}</div>}

        {activeTab === 'play' && <div className="dashboardGrid"><section className="panel wide"><h2>Play and enrichment</h2><p>Track favorite toys, safe places, play minutes, games, rewards, and enrichment routines.</p><button className="primary" type="button" onClick={() => setState({ ...state, play: [{ id: Date.now(), activity: 'New play activity', toy: 'Toy', place: 'Place', minutes: 10, favorite: false, notes: 'Editable notes' }, ...state.play] })}>Add play activity</button></section>{state.play.map((item) => <section className="panel" key={item.id}><Field label="Activity" value={item.activity} onChange={(v) => setState({ ...state, play: state.play.map((play) => play.id === item.id ? { ...play, activity: v } : play) })} /><Field label="Toy / reward" value={item.toy} onChange={(v) => setState({ ...state, play: state.play.map((play) => play.id === item.id ? { ...play, toy: v } : play) })} /><Field label="Place" value={item.place} onChange={(v) => setState({ ...state, play: state.play.map((play) => play.id === item.id ? { ...play, place: v } : play) })} /><Field label="Minutes" type="number" value={String(item.minutes)} onChange={(v) => setState({ ...state, play: state.play.map((play) => play.id === item.id ? { ...play, minutes: Number(v) || 0 } : play) })} /><label className="toggleRow"><input type="checkbox" checked={item.favorite} onChange={(event) => setState({ ...state, play: state.play.map((play) => play.id === item.id ? { ...play, favorite: event.target.checked } : play) })} /> Favorite</label><TextArea label="Notes" value={item.notes} onChange={(v) => setState({ ...state, play: state.play.map((play) => play.id === item.id ? { ...play, notes: v } : play) })} /></section>)}</div>}

        {activeTab === 'training' && <div className="dashboardGrid"><section className="panel wide"><h2>Training, tricks, and commands</h2><p>Track commands, cues, proofing level, points, categories, and notes. Useful for basic obedience, CGC-style goals, service tasks, therapy manners, and custom tricks.</p><button className="primary" type="button" onClick={() => setState({ ...state, training: [{ id: Date.now(), command: 'New command', category: 'Custom', cue: 'Cue', status: 'Not started', points: 20, notes: 'Training notes' }, ...state.training] })}>Add command/trick</button></section>{state.training.map((item) => <section className="panel" key={item.id}><Field label="Command / trick" value={item.command} onChange={(v) => setState({ ...state, training: state.training.map((row) => row.id === item.id ? { ...row, command: v } : row) })} /><SelectField label="Category" value={item.category} options={['Basic obedience','Leash manners','Recall','Trick','Service task','Therapy manners','Safety','Custom']} onChange={(v) => setState({ ...state, training: state.training.map((row) => row.id === item.id ? { ...row, category: v } : row) })} /><Field label="Cue" value={item.cue} onChange={(v) => setState({ ...state, training: state.training.map((row) => row.id === item.id ? { ...row, cue: v } : row) })} /><SelectField label="Status" value={item.status} options={trainingStatuses} onChange={(v) => setState({ ...state, training: state.training.map((row) => row.id === item.id ? { ...row, status: v } : row) })} /><Field label="Points" type="number" value={String(item.points)} onChange={(v) => setState({ ...state, training: state.training.map((row) => row.id === item.id ? { ...row, points: Number(v) || 0 } : row) })} /><TextArea label="Notes" value={item.notes} onChange={(v) => setState({ ...state, training: state.training.map((row) => row.id === item.id ? { ...row, notes: v } : row) })} /><button type="button" onClick={() => awardXp(item.points, `${item.command} training logged`)}>Log points</button></section>)}</div>}

        {activeTab === 'lost' && <div className="dashboardGrid"><section className="panel wide"><h2>Lost/found notification center</h2><p>Flip lost mode, stage finder reports, and keep owner-approved public return-home information together.</p><div className="alertBanner"><strong>{lostAlertCount > 0 ? `🔴 ${lostAlertCount} active lost/found alert${lostAlertCount > 1 ? 's' : ''}` : 'No active lost/found alerts'}</strong><span>Finder scan reports save GPS only after consent on the NFC scan gate.</span></div><div className="actions"><button className="primary dangerButton" type="button" onClick={reportLostFromOwner}>Report my dog lost + save location</button><button type="button" onClick={() => addLostReport('Open')}>Create manual report</button><button type="button" onClick={() => { patchSettings({ shareLastScan: true }); setMessage('Last scan sharing enabled for lost/found mode.'); }}>Share last scan</button></div></section>{state.lostReports.map((report) => <section className="panel" key={report.id}><SelectField label="Status" value={report.status} options={['Open','Searching','Owner contacted','Resolved','False alarm']} onChange={(v) => setState({ ...state, lostReports: state.lostReports.map((item) => item.id === report.id ? { ...item, status: v } : item) })} /><SelectField label="Alert type" value={report.status} options={['Open','Searching','Finder reported','Owner contacted','Resolved','False alarm']} onChange={(v) => setState({ ...state, lostReports: state.lostReports.map((item) => item.id === report.id ? { ...item, status: v } : item) })} /><Field label="Location" value={report.location} onChange={(v) => setState({ ...state, lostReports: state.lostReports.map((item) => item.id === report.id ? { ...item, location: v } : item) })} /><TextArea label="Note" value={report.note} onChange={(v) => setState({ ...state, lostReports: state.lostReports.map((item) => item.id === report.id ? { ...item, note: v } : item) })} /><p>{report.time}</p></section>)}</div>}

        {activeTab === 'pack' && <div className="dashboardGrid"><section className="panel wide"><p className="eyebrow">Dog Pack</p><h2>Friends, groups, park plans, and chat</h2><div className="grid2"><SelectField label="Group" value={packGroup} options={state.packGroups} onChange={setPackGroup} /><Field label="Message" value={packDraft} onChange={setPackDraft} /><Field label="New/edit group" value={customGroup} onChange={setCustomGroup} /></div><div className="actions"><button className="primary" type="button" onClick={sendPackMessage}>Send message</button><button type="button" onClick={addPackGroup}>Save group</button><button type="button" onClick={() => setState({ ...state, packFriends: [{ id: Date.now(), name: 'New friend', dog: 'New dog', group: packGroup, status: 'Invite sent', activity: 'Waiting for approval' }, ...state.packFriends] })}>Add friend</button></div><div className="chipCloud">{state.packGroups.map((group) => <span key={group}>{group} <button type="button" onClick={() => setState({ ...state, packGroups: state.packGroups.filter((item) => item !== group) })}>×</button></span>)}</div></section>{state.packFriends.map((friend) => <section className="panel" key={friend.id}><Field label="Friend" value={friend.name} onChange={(v) => setState({ ...state, packFriends: state.packFriends.map((item) => item.id === friend.id ? { ...item, name: v } : item) })} /><Field label="Dog" value={friend.dog} onChange={(v) => setState({ ...state, packFriends: state.packFriends.map((item) => item.id === friend.id ? { ...item, dog: v } : item) })} /><SelectField label="Group" value={friend.group} options={state.packGroups} onChange={(v) => setState({ ...state, packFriends: state.packFriends.map((item) => item.id === friend.id ? { ...item, group: v } : item) })} /><p>{friend.status} • {friend.activity}</p></section>)}<section className="panel wide"><h3>Pack chat</h3>{state.packMessages.map((chat) => <div className="chatBubble" key={chat.id}><strong>{chat.author}</strong><span>{chat.group} • {chat.time}</span><p>{chat.text}</p><button type="button" onClick={() => setState({ ...state, packMessages: state.packMessages.filter((item) => item.id !== chat.id) })}>Delete message</button></div>)}</section></div>}

        {activeTab === 'goals' && <div className="dashboardGrid"><section className="panel wide"><h2>Goals, points, and achievements</h2><div className="grid2"><Field label="Weekly walk distance" type="number" value={String(state.goals.weeklyMiles)} onChange={(v) => setState({ ...state, goals: { ...state.goals, weeklyMiles: Number(v) || 0 } })} /><Field label="Meals per day" type="number" value={String(state.goals.mealsPerDay)} onChange={(v) => setState({ ...state, goals: { ...state.goals, mealsPerDay: Number(v) || 0 } })} /><Field label="Weekly care tasks" type="number" value={String(state.goals.careTasks)} onChange={(v) => setState({ ...state, goals: { ...state.goals, careTasks: Number(v) || 0 } })} /><Field label="Training sessions" type="number" value={String(state.goals.trainingSessions)} onChange={(v) => setState({ ...state, goals: { ...state.goals, trainingSessions: Number(v) || 0 } })} /><Field label="Play minutes" type="number" value={String(state.goals.playMinutes)} onChange={(v) => setState({ ...state, goals: { ...state.goals, playMinutes: Number(v) || 0 } })} /><Field label="Current XP" type="number" value={String(state.goals.currentXp)} onChange={(v) => setState({ ...state, goals: { ...state.goals, currentXp: Number(v) || 0, level: Math.max(1, Math.floor((Number(v) || 0) / 250) + 1) } })} /></div><div className="levelBadge">Level {state.goals.level}<div className="progress"><span style={{ width: `${state.goals.currentXp % 250 / 2.5}%` }} /></div>{state.goals.currentXp + earnedXp} XP including achievements</div><div className="actions"><button type="button" onClick={() => awardXp(20, 'care task completed')}>Complete care task</button><button type="button" onClick={() => awardXp(35, 'goal streak completed')}>Complete streak</button><button type="button" onClick={() => awardXp(25, 'play session logged')}>Log play points</button><button type="button" onClick={() => setState({ ...state, achievements: [{ id: Date.now(), title: 'New achievement', category: 'Custom', points: 25, earned: false, requirement: 'Define requirement' }, ...state.achievements] })}>Add achievement</button></div></section>{state.achievements.map((item) => <section className="panel" key={item.id}><h3>{item.title}</h3><p>{item.category} • {item.points} pts</p><p>{item.requirement}</p><label className="toggleRow"><input type="checkbox" checked={item.earned} onChange={(event) => setState({ ...state, achievements: state.achievements.map((row) => row.id === item.id ? { ...row, earned: event.target.checked } : row) })} /> Earned</label></section>)}</div>}

        {activeTab === 'settings' && <div className="dashboardGrid"><section className="panel wide"><h2>Settings, privacy, and app look</h2>{Object.entries(state.settings).map(([key, value]) => typeof value === 'boolean' ? <label className="toggleRow" key={key}><input type="checkbox" checked={value} onChange={(event) => patchSettings({ [key]: event.target.checked } as Partial<typeof state.settings>)} /> {key}</label> : null)}<div className="grid2"><SelectField label="Units" value={state.settings.units} options={['miles','kilometers']} onChange={(v) => patchSettings({ units: v })} /><SelectField label="Privacy mode" value={state.settings.privacyMode} options={['strict','balanced','open during lost mode']} onChange={(v) => patchSettings({ privacyMode: v })} /><SelectField label="Map style" value={state.settings.mapStyle} options={['standard map','satellite-ready','city grid','trail map']} onChange={(v) => patchSettings({ mapStyle: v })} /><SelectField label="Default walk end" value={state.settings.defaultWalkEnd} options={['destination','start','home','custom']} onChange={(v) => patchSettings({ defaultWalkEnd: v as WalkEndMode })} /><SelectField label="App color palette" value={state.palette} options={['forest','ocean','sunset','mono']} onChange={(v) => setState({ ...state, palette: v as Palette })} /><SelectField label="Theme" value={state.theme} options={['dark','light']} onChange={(v) => setState({ ...state, theme: v as Theme })} /></div></section><section className="panel"><h3>Scan URLs</h3><p>NFC/QR:</p><code>{publicUrl}</code><p>Read-only:</p><code>{readOnlyUrl}</code></section></div>}

        {activeTab === 'admin' && canSeeAdmin && <div className="dashboardGrid"><section className="panel wide"><h2>Admin console</h2><div className="notificationDock"><span>🔔 3</span><span>📍 1</span><span>🩺 {state.records.length}</span><span>💬 {state.packMessages.length}</span><span>🏆 {state.achievements.filter((item) => item.earned).length}</span></div><p>Customize app colors/features, switch between admin/user mode, edit users, stage pet profiles, and manage routes. Secret operations still need Supabase Edge Functions before production.</p><div className="serviceGrid"><div className={`servicePill ${hasSupabaseConfig ? 'green' : 'yellow'}`}><span />Supabase {hasSupabaseConfig ? 'configured' : 'needs public env'}</div><div className="servicePill green"><span />GitHub Pages static app</div><div className="servicePill green"><span />Local browser storage</div><div className="servicePill yellow"><span />Edge Functions not deployed</div></div><div className="grid2"><SelectField label="Global palette" value={state.palette} options={['forest','ocean','sunset','mono']} onChange={(v) => setState({ ...state, palette: v as Palette })} /><SelectField label="Admin account plan" value={state.tier} options={Object.keys(tiers)} onChange={(v) => setState({ ...state, tier: v as keyof typeof tiers })} /><Field label="New user name" value={userDraft.name} onChange={(v) => setUserDraft({ ...userDraft, name: v })} /><Field label="New user email" value={userDraft.email} onChange={(v) => setUserDraft({ ...userDraft, email: v })} /></div><div className="adminActions"><button className="primary" type="button" onClick={() => { patchPet({ tagId: `tag-${Math.random().toString(36).slice(2, 8)}` }); setMessage('New tag code generated locally. Production should mint this server-side.'); }}>Generate tag ID</button><button type="button" onClick={addManagedUser}>Create/invite user</button><button type="button" onClick={() => setState({ ...state, adminMode: !state.adminMode })}>Switch admin/user</button><button type="button" onClick={() => setMessage('Patreon sync requires client secret/creator token on an Edge Function, not in browser.')}>Sync Patreon</button><button type="button" onClick={() => setState(defaultState)}>Reset demo data</button></div></section>{state.managedUsers.map((user) => <section className="panel" key={user.id}><h3>{user.name}</h3><p>{user.role} • {user.status}</p><p>{user.email}</p><SelectField label="Plan" value={user.plan} options={Object.keys(tiers)} onChange={(v) => setState({ ...state, managedUsers: state.managedUsers.map((item) => item.id === user.id ? { ...item, plan: v as keyof typeof tiers } : item) })} /><button type="button" onClick={() => setMessage(`Opened editable admin route for ${user.name}.`)}>Edit account</button></section>)}</div>}

        {sectionNav()}
      </section>
    </main>
  );
}
